// ... (mismos imports)

// Cambia solo estas funciones dentro de GestionOfertas:

  const buscarMatch = useCallback((texto) => {
    if (!texto || texto.length < 3) return null;
    const norm = (t) => t.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z0-9]/g, '');
    const textoBusqueda = norm(texto);

    // Buscamos si el nombre de la foto contiene el texto del producto o viceversa
    return galeria.find(f => {
      const nombreFoto = norm(f.nombreReferencia);
      return nombreFoto.includes(textoBusqueda) || textoBusqueda.includes(nombreFoto);
    });
  }, [galeria]);

  const renderFoto = (pid, size = "w_150,h_150") => {
    if (!pid || pid === 'placeholder_id') {
      return (
        <div style={{ width: 50, height: 50, background: '#f1f5f9', borderRadius: 8, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <ImageIcon color="#cbd5e1" size={20}/>
        </div>
      );
    }

    // Buscamos la URL real en la galería para evitar errores de nombres con puntos (.2k)
    const fotoInfo = galeria.find(g => g.publicId === pid);
    let urlFinal;

    if (fotoInfo && fotoInfo.url) {
      // Usamos la URL guardada y le inyectamos la transformación de tamaño
      urlFinal = fotoInfo.url.replace('/upload/', `/upload/${size},c_fill,f_auto,q_auto/`);
    } else {
      // Fallback si no está en la galería local
      urlFinal = `https://res.cloudinary.com/${CLOUD_NAME}/image/upload/${size},c_fill/f_auto,q_auto/${pid}`;
    }

    return (
      <div style={{ width: 50, height: 50, background: '#f1f5f9', borderRadius: 8, overflow: 'hidden', border: '1px solid #e2e8f0', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <img 
          src={urlFinal} 
          style={{ width: '100%', height: '100%', objectFit: 'cover' }} 
          alt="Producto"
          onError={(e) => {
            e.target.onerror = null;
            e.target.style.display = 'none';
            // En lugar de innerHTML, usamos el estado natural de la imagen
            e.target.parentNode.style.background = '#fee2e2'; 
          }}
        />
      </div>
    );
  };
